class _Node:
    __slots__ = ("val", "next")
    def __init__(self, val):
        self.val = val
        self.next = None


def has_cycle(values, pos):
    if not values:
        return False

    nodes = [_Node(v) for v in values]
    for i in range(len(nodes) - 1):
        nodes[i].next = nodes[i + 1]
    if pos != -1:
        nodes[-1].next = nodes[pos]

    slow = fast = nodes[0]
    while fast is not None and fast.next is not None:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            return True
    return False
